import { entriesOfPhpAssoc, toPhpArrayObject } from "../_helpers/_phpTypes.js";
export function array_diff_assoc(arr1, ...arrays) {
    //  discuss at: https://locutus.io/php/array_diff_assoc/
    // original by: Kevin van Zonneveld (https://kvz.io)
    // bugfixed by: 0m3r
    //  revised by: Brett Zamir (https://brett-zamir.me)
    //   example 1: array_diff_assoc({0: 'Kevin', 1: 'van', 2: 'Zonneveld'}, {0: 'Kevin', 4: 'van', 5: 'Zonneveld'})
    //   returns 1: {1: 'van', 2: 'Zonneveld'}
    const retArr = {};
    if (arrays.length < 1) {
        return retArr;
    }
    const arr1Object = toPhpArrayObject(arr1);
    arr1keys: for (const [k1, arr1Value] of entriesOfPhpAssoc(arr1Object)) {
        for (const nextArray of arrays) {
            const arr = toPhpArrayObject(nextArray);
            for (const [k, value] of entriesOfPhpAssoc(arr)) {
                if (value === arr1Value && k === k1) {
                    continue arr1keys;
                }
            }
        }
        retArr[k1] = arr1Value;
    }
    return retArr;
}
